I'll create an interactive HTML web demo that showcases the web scraper functionality with a beautiful UI. Here's a complete single-file application:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Web Scraper Demo - Interactive Tool</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            padding: 20px;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
        }

        .header {
            text-align: center;
            color: white;
            margin-bottom: 30px;
        }

        .header h1 {
            font-size: 2.5em;
            margin-bottom: 10px;
            text-shadow: 2px 2px 4px rgba(0,0,0,0.2);
        }

        .header p {
            font-size: 1.1em;
            opacity: 0.9;
        }

        .demo-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin-bottom: 20px;
        }

        .card {
            background: white;
            border-radius: 15px;
            padding: 25px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.2);
            transition: transform 0.3s;
        }

        .card:hover {
            transform: translateY(-5px);
        }

        .card.full-width {
            grid-column: 1 / -1;
        }

        .card h3 {
            color: #667eea;
            margin-bottom: 20px;
            font-size: 1.3em;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .card h3 .icon {
            width: 30px;
            height: 30px;
            background: linear-gradient(135deg, #667eea, #764ba2);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 16px;
        }

        .input-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            margin-bottom: 5px;
            color: #555;
            font-weight: 500;
        }

        input, select, textarea {
            width: 100%;
            padding: 10px 15px;
            border: 2px solid #e0e0e0;
            border-radius: 8px;
            font-size: 14px;
            transition: border-color 0.3s;
        }

        input:focus, select:focus, textarea:focus {
            outline: none;
            border-color: #667eea;
        }

        textarea {
            resize: vertical;
            min-height: 80px;
            font-family: monospace;
        }

        button {
            background: linear-gradient(135deg, #667eea, #764ba2);
            color: white;
            border: none;
            padding: 12px 25px;
            border-radius: 8px;
            font-size: 16px;
            cursor: pointer;
            transition: transform 0.2s, box-shadow 0.2s;
            font-weight: 500;
        }

        button:hover {
            transform: translateY(-2px);
            box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
        }

        button:active {
            transform: translateY(0);
        }

        button:disabled {
            opacity: 0.6;
            cursor: not-allowed;
            transform: none;
        }

        .btn-secondary {
            background: #6c757d;
        }

        .result-area {
            background: #f8f9fa;
            border-radius: 8px;
            padding: 15px;
            max-height: 400px;
            overflow-y: auto;
            font-family: monospace;
            font-size: 13px;
            white-space: pre-wrap;
            word-break: break-word;
            border: 2px solid #e0e0e0;
        }

        .status {
            display: inline-block;
            padding: 5px 12px;
            border-radius: 20px;
            font-size: 12px;
            font-weight: 500;
            margin-left: 10px;
        }

        .status.idle {
            background: #e0e0e0;
            color: #666;
        }

        .status.loading {
            background: #fff3cd;
            color: #856404;
        }

        .status.success {
            background: #d4edda;
            color: #155724;
        }

        .status.error {
            background: #f8d7da;
            color: #721c24;
        }

        .stats-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 15px;
            margin-bottom: 20px;
        }

        .stat-box {
            background: linear-gradient(135deg, #667eea, #764ba2);
            color: white;
            padding: 15px;
            border-radius: 10px;
            text-align: center;
        }

        .stat-box .value {
            font-size: 2em;
            font-weight: bold;
        }

        .stat-box .label {
            font-size: 0.9em;
            opacity: 0.9;
            margin-top: 5px;
        }

        .example-links {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            margin-top: 10px;
        }

        .example-link {
            background: #f0f0f0;
            padding: 8px 15px;
            border-radius: 20px;
            cursor: pointer;
            font-size: 13px;
            transition: background 0.3s;
        }

        .example-link:hover {
            background: #667eea;
            color: white;
        }

        .loading-spinner {
            display: inline-block;
            width: 20px;
            height: 20px;
            border: 3px solid rgba(255,255,255,.3);
            border-radius: 50%;
            border-top-color: #fff;
            animation: spin 1s ease-in-out infinite;
            margin-right: 8px;
        }

        @keyframes spin {
            to { transform: rotate(360deg); }
        }

        .progress-bar {
            width: 100%;
            height: 4px;
            background: #e0e0e0;
            border-radius: 2px;
            overflow: hidden;
            margin: 10px 0;
        }

        .progress-bar .fill {
            height: 100%;
            background: linear-gradient(135deg, #667eea, #764ba2);
            transition: width 0.3s;
        }

        @media (max-width: 768px) {
            .demo-grid {
                grid-template-columns: 1fr;
            }

            .stats-grid {
                grid-template-columns: 1fr;
            }
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>🔍 Web Scraper Demo</h1>
            <p>Interactive demonstration of web scraping capabilities</p>
        </div>

        <div class="stats-grid">
            <div class="stat-box">
                <div class="value" id="totalScrapes">0</div>
                <div class="label">Total Scrapes</div>
            </div>
            <div class="stat-box">
                <div class="value" id="successRate">0%</div>
                <div class="label">Success Rate</div>
            </div>
            <div class="stat-box">
                <div class="value" id="dataPoints">0</div>
                <div class="label">Data Points</div>
            </div>
        </div>

        <div class="demo-grid">
            <!-- Configuration Card -->
            <div class="card">
                <h3>
                    <span class="icon">⚙️</span>
                    Scraper Configuration
                </h3>
                <div class="input-group">
                    <label>Target URL</label>
                    <input type="url" id="urlInput" placeholder="https://example.com" value="">
                </div>
                <div class="input-group">
                    <label>Scraping Template</label>
                    <select id="templateSelect">
                        <option value="custom">Custom Extraction</option>
                        <option value="news">News Articles</option>
                        <option value="products">Product Listings</option>
                        <option value="table">Table Data</option>
                    </select>
                </div>
                <div class="input-group" id="selectorGroup">
                    <label>CSS Selector (for custom extraction)</label>
                    <input type="text" id="selectorInput" placeholder="e.g., h1, .article-title, p.content">
                </div>
                <div class="input-group">
                    <label>Request Delay (seconds)</label>
                    <input type="number" id="delayInput" value="1" min="0" max="10" step="0.5">
                </div>
                <div class="input-group">
                    <label>Output Format</label>
                    <select id="formatSelect">
                        <option value="json">JSON</option>
                        <option value="csv">CSV</option>
                    </select>
                </div>
                <div style="display: flex; gap: 10px;">
                    <button onclick="startScraping()" id="scrapeBtn">
                        🚀 Start Scraping
                    </button>
                    <button onclick="clearResults()" class="btn-secondary">
                        🗑️ Clear
                    </button>
                </div>
                <div class="progress-bar" style="display: none;" id="progressBar">
                    <div class="fill" style="width: 0%;" id="progressFill"></div>
                </div>
            </div>

            <!-- Results Card -->
            <div class="card">
                <h3>
                    <span class="icon">📊</span>
                    Results 
                    <span class="status idle" id="statusBadge">Idle</span>
                </h3>
                <div class="result-area" id="resultArea">
                    <span style="color: #999;">Waiting for scraping job...</span>
                </div>
                <div style="margin-top: 15px; display: flex; gap: 10px;">
                    <button onclick="copyResults()" id="copyBtn" disabled>
                        📋 Copy Results
                    </button>
                    <button onclick="downloadResults()" id="downloadBtn" disabled>
                        💾 Download
                    </button>
                </div>
            </div>

            <!-- Example URLs Card -->
            <div class="card full-width">
                <h3>
                    <span class="icon">💡</span>
                    Example URLs & Selectors
                </h3>
                <div class="example-links">
                    <span class="example-link" onclick="setExample('https://books.toscrape.com', 'products', '.product_pod')">
                        📚 Books to Scrape
                    </span>
                    <span class="example-link" onclick="setExample('https://quotes.toscrape.com', 'custom', '.quote .text')">
                        💬 Quotes Website
                    </span>
                    <span class="example-link" onclick="setExample('https://en.wikipedia.org/wiki/Web_scraping', 'custom', '#mw-content-text p')">
                        📖 Wikipedia Article
                    </span>
                    <span class="example-link" onclick="setExample('https://news.ycombinator.com', 'news', '.athing')">
                        🗞️ Hacker News
                    </span>
                </div>
            </div>

            <!-- Extracted Data Preview Card -->
            <div class="card full-width">
                <h3>
                    <span class="icon">📋</span>
                    Data Preview Table
                </h3>
                <div id="tablePreview" style="overflow-x: auto;">
                    <p style="color: #999;">Extracted data will appear here in table format...</p>
                </div>
            </div>
        </div>
    </div>

    <script>
        // State management
        let scrapedData = null;
        let stats = {
            totalScrapes: 0,
            successfulScrapes: 0,
            totalDataPoints: 0
        };

        // Simulated scraping function (in real implementation, this would connect to a backend)
        async function simulateScraping(url, template, selector, delay, format) {
            // This is a demo simulation - in production, this would make API calls to the Python backend
            const startTime = Date.now();

            // Simulate processing delay
            await new Promise(resolve => setTimeout(resolve, delay * 1000 + Math.random() * 1000));

            // Generate demo data based on template
            let data;
            switch(template) {
                case 'news':
                    data = generateNewsData(url);
                    break;
                case 'products':
                    data = generateProductData(url);
                    break;
                case 'table':
                    data = generateTableData(url);
                    break;
                case 'custom':
                    data = generateCustomData(url, selector);
                    break;
                default:
                    data = generateCustomData(url, selector);
            }

            return {
                data: data,
                metadata: {
                    url: url,
                    template: template,
                    selector: selector,
                    timestamp: new Date().toISOString(),
                    duration: ((Date.now() - startTime) / 1000).toFixed(2),
                    itemsCount: Array.isArray(data) ? data.length : 1
                }
            };
        }

        // Demo data generators
        function generateNewsData(url) {
            const articles = [];
            const titles = [
                "Breaking: Major Tech Innovation Announced",
                "Global Markets Show Positive Trends",
                "New Environmental Policy Changes Proposed",
                "Sports Championship Results Revealed",
                "Healthcare Breakthrough Research Published"
            ];
            const summaries = [
                "A groundbreaking development in technology sector...",
                "International markets demonstrate strong recovery...",
                "Government officials propose new regulations...",
                "Exciting finale to the championship series...",
                "Scientists publish revolutionary findings..."
            ];

            for (let i = 0; i < 5; i++) {
                articles.push({
                    title: titles[i],
                    link: `${url}/article/${i + 1}`,
                    summary: summaries[i],
                    date: new Date(Date.now() - Math.random() * 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
                    author: `Author ${i + 1}`
                });
            }
            return articles;
        }

        function generateProductData(url) {
            const products = [];
            const names = ["Wireless Headphones", "Smart Watch", "Laptop Stand", "USB-C Hub", "Mechanical Keyboard"];
            const prices = [79.99, 199.99, 45.00, 34.99, 129.99];

            for (let i = 0; i < 5; i++) {
                products.push({
                    name: names[i],
                    price: `$${prices[i]}`,
                    description: `High-quality ${names[i].toLowerCase()} with premium features`,
                    rating: (Math.random() * 2 + 3).toFixed(1),
                    reviews: Math.floor(Math.random() * 500 + 50),
                    inStock: Math.random() > 0.2
                });
            }
            return products;
        }

        function generateTableData(url) {
            const rows = [];
            for (let i = 0; i < 8; i++) {
                rows.push({
                    id: i + 1,
                    name: `Item ${i + 1}`,
                    category: ['Electronics', 'Books', 'Clothing', 'Food'][Math.floor(Math.random() * 4)],
                    value: `$${(Math.random() * 100).toFixed(2)}`,
                    status: Math.random() > 0.3 ? 'Active' : 'Inactive'
                });
            }
            return rows;
        }

        function generateCustomData(url, selector) {
            if (!selector) {
                return {
                    title: "Demo Page Title",
                    content: "This is simulated content extracted from the webpage. In a real scenario, this would contain the actual text content from the target URL.",
                    links: ["/page1", "/page2", "/page3"],
                    metadata: {
                        description: "A sample meta description",
                        keywords: "demo, scraper, web"
                    }
                };
            }

            // Simulate selector-based extraction
            const elements = [];
            for (let i = 0; i < 3; i++) {
                elements.push(`Extracted content from ${selector} - Element ${i + 1}: This demonstrates how CSS selectors target specific elements on a webpage.`);
            }
            return elements;
        }

        // Main scraping function
        async function startScraping() {
            const url = document.getElementById('urlInput').value;
            const template = document.getElementById('templateSelect').value;
            const selector = document.getElementById('selectorInput').value;
            const delay = parseFloat(document.getElementById('delayInput').value) || 1;
            const format = document.getElementById('formatSelect').value;

            if (!url) {
                alert('Please enter a URL to scrape');
                return;
            }

            // Update UI for loading state
            const scrapeBtn = document.getElementById('scrapeBtn');
            const statusBadge = document.getElementById('statusBadge');
            const progressBar = document.getElementById('progressBar');
            const progressFill = document.getElementById('progressFill');

            scrapeBtn.disabled = true;
            scrapeBtn.innerHTML = '<span class="loading-spinner"></span> Scraping...';
            statusBadge.className = 'status loading';
            statusBadge.textContent = 'Scraping...
